import base64
import requests
import uuid
from datetime import datetime
from lxml import etree

class SAMLServiceProvider:
    def __init__(self, destination_url, user_info):
        self.destination_url = destination_url
        self.user_info = user_info
    
    def build_authn_request(self):
        request_id = f"id_{uuid.uuid4()}"
        issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
        saml_request = f"""
        <samlp:AuthnRequest
            xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
            xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
            ID="{request_id}"
            IssueInstant="{issue_instant}"
            Version="2.0"
            Destination="{self.destination_url}">
            <saml:Issuer>your-issuer-identifier</saml:Issuer>
            <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
            <samlp:Subject>
                <saml:NameID>{self.user_info['email']}</saml:NameID>
            </samlp:Subject>
        </samlp:AuthnRequest>
        """
        return saml_request.strip()
    
    def send_authn_request(self):
        saml_request = self.build_authn_request()
        encoded_request = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')
        payload = {'SAMLRequest': encoded_request}

        response = requests.post(self.destination_url, data=payload)
        return response

